	  manuscript_create_project_action: { en: "Open in Writer OS · Rewrite", it: "Apri in Writer OS · Rewrite", es: "Abrir en Writer OS · Rewrite", fr: "Ouvrir dans Writer OS · Rewrite", de: "In Writer OS · Rewrite öffnen" },
	  manuscript_project_created: { en: "Manuscript imported. Rewrite advice is ready in the editor.", it: "Manoscritto importato. I consigli di riscrittura sono pronti nell'editor.", es: "Manuscrito importado. Los consejos de reescritura están listos en el editor.", fr: "Manuscrit importé. Les conseils de réécriture sont prêts dans l'éditeur.", de: "Manuskript importiert. Die Überarbeitungshinweise sind im Editor bereit." },
	  manuscript_project_create_error: { en: "Could not create the manuscript project.", it: "Impossibile creare il progetto manoscritto.", es: "No se pudo crear el proyecto del manuscrito.", fr: "Impossible de créer le projet de manuscrit.", de: "Manuskriptprojekt konnte nicht erstellt werden." },
