	  manuscript_unsupported_file: { en: "Unsupported file. Use TXT, Markdown, or DOCX.", it: "File non supportato. Usa TXT, Markdown o DOCX.", es: "Archivo no compatible. Usa TXT, Markdown o DOCX.", fr: "Fichier non pris en charge. Utilisez TXT, Markdown ou DOCX.", de: "Datei nicht unterstützt. Nutze TXT, Markdown oder DOCX." },
	  manuscript_min_text_error: { en: "Add at least {count} words before analysis.", it: "Aggiungi almeno {count} parole prima dell'analisi.", es: "Añade al menos {count} palabras antes del análisis.", fr: "Ajoutez au moins {count} mots avant l'analyse.", de: "Füge vor der Analyse mindestens {count} Wörter hinzu." },
