	  rewrite_mode_hint: { en: "Rewrite mode — use the ✨ menu on this chapter for Light, Deep, or Bestseller rewrite.", it: "Modalità rewrite — usa il menu ✨ su questo capitolo per Light, Deep o Bestseller.", es: "Modo reescritura — usa el menú ✨ en este capítulo.", fr: "Mode réécriture — utilisez le menu ✨ sur ce chapitre.", de: "Rewrite-Modus — nutze das ✨-Menü für Light-, Deep- oder Bestseller-Rewrite." },
